  1→import { useRef, useCallback, useMemo } from 'react';
  2→import { getStarColor, getStarRadius, simpleHash } from '../utils/starUtils';
  3→
  4→// ── Constants ──────────────────────────────────────────────────────────
  5→const MAX_SPEED = 12;
  6→const ACCEL = 0.25;
  7→const BRAKE = 0.15;
  8→const FRICTION = 0.985;
  9→const YAW_RATE = 0.035;
 10→const PITCH_RATE = 0.025;
 11→const PITCH_MAX = (89 * Math.PI) / 180; // 89° in radians
 12→const MIN_VIEW_Z = 0.5;
 13→const SPAWN_DIST = 800;
 14→const RECYCLE_Z = 1200;
 15→const SORT_INTERVAL = 5;
 16→const TARGET_DIST_MAX = 150;
 17→const TARGET_Z_MIN = 2;
 18→const TWO_PI = Math.PI * 2;
 19→
 20→// ── Docking constants ─────────────────────────────────────────────────
 21→const DOCKING_THRESHOLD_Z = 18;
 22→const DOCKING_CENTER_MAX = 50;
 23→const MAGNET_THRESHOLD_Z = 80;
 24→const MAGNET_STRENGTH = 0.015;
 25→const DOCK_ACCEL = 0.5;
 26→const DOCK_MAX_SPEED = 8;
 27→
 28→/** Max viewZ at which labels start fading in */
 29→export const LABEL_Z_MAX = 800;
 30→
 31→/** Export docking thresholds for external use */
 32→export { MAGNET_THRESHOLD_Z };
 33→
 34→/** Parse "#5f92ff" → { r, g, b } */
 35→const parseHex = (hex) => ({
 36→    r: parseInt(hex.slice(1, 3), 16),
 37→    g: parseInt(hex.slice(3, 5), 16),
 38→    b: parseInt(hex.slice(5, 7), 16),
 39→});
 40→
 41→/** Seeded pseudo-random from integer seed */
 42→const seededRandom = (seed) => {
 43→    let s = seed | 0;
 44→    return () => {
 45→        s = (s * 1664525 + 1013904223) | 0;
 46→        return ((s >>> 0) / 4294967296);
 47→    };
 48→};
 49→
 50→/** Get forward direction vector from yaw + pitch */
 51→const getForwardVector = (yaw, pitch) => ({
 52→    x: Math.sin(yaw) * Math.cos(pitch),
 53→    y: Math.sin(pitch),
 54→    z: Math.cos(yaw) * Math.cos(pitch),
 55→});
 56→
 57→const useRocketMode = () => {
 58→    const isActiveRef = useRef(false);
 59→    const camPosRef = useRef({ x: 0, y: 0, z: 0 });
 60→    const yawRef = useRef(0);
 61→    const pitchRef = useRef(0);
 62→    const velocityRef = useRef(0);
 63→    const starsRef = useRef([]);
 64→    const sortedIndicesRef = useRef([]);
 65→    const keysRef = useRef({ w: false, s: false, a: false, d: false, q: false, e: false });
 66→    const targetIndexRef = useRef(-1);
 67→    const frameRef = useRef(0);
 68→    const layerRef = useRef(null);
 69→    const rafRef = useRef(null);
 70→    const stageSizeRef = useRef({ width: 0, height: 0 });
 71→    const onKeyDownRef = useRef(null);
 72→    const onKeyUpRef = useRef(null);
 73→
 74→    // ── Docking refs ──────────────────────────────────────────────────
 75→    const dockingStateRef = useRef('none'); // 'none' | 'magnet' | 'approaching' | 'flash' | 'done'
 76→    const dockingTargetIdxRef = useRef(-1);
 77→    const dockingProgressRef = useRef(0);
 78→    const dockingStartTimeRef = useRef(0);
 79→    const dockingCallbackRef = useRef(null);
 80→    const autoDockCbRef = useRef(null); // persistent auto-dock callback, survives manual docking
 81→    const inputFrozenRef = useRef(false);
 82→    const dockingStarScaleRef = useRef(1);
 83→    const dockCooldownRef = useRef(0); // timestamp — suppress auto-dock until this time
 84→    const galaxyCenterRef = useRef({ x: 0, y: 0 });
 85→
 86→    const sortStars = useCallback(() => {
 87→        const stars = starsRef.current;
 88→        const indices = sortedIndicesRef.current;
 89→        // Insertion sort — fast for nearly-sorted arrays, sort by viewZ descending (far first)
 90→        for (let i = 1; i < indices.length; i++) {
 91→            const key = indices[i];
 92→            let j = i - 1;
 93→            while (j >= 0 && stars[indices[j]].viewZ < stars[key].viewZ) {
 94→                indices[j + 1] = indices[j];
 95→                j--;
 96→            }
 97→            indices[j + 1] = key;
 98→        }
 99→    }, []);
100→
101→    const tick = useCallback(() => {
102→        if (!isActiveRef.current) return;
103→
104→        const keys = keysRef.current;
105→        const cam = camPosRef.current;
106→        const stars = starsRef.current;
107→        const size = stageSizeRef.current;
108→        const dockState = dockingStateRef.current;
109→
110→        // ── Input processing (frozen during docking) ──────────────────
111→        if (!inputFrozenRef.current) {
112→            // ── Yaw (A/D) ─────────────────────────────────────────────
113→            if (keys.a) yawRef.current -= YAW_RATE;
114→            if (keys.d) yawRef.current += YAW_RATE;
115→
116→            // ── Pitch (Q/E), clamped ──────────────────────────────────
117→            if (keys.q) pitchRef.current = Math.min(pitchRef.current + PITCH_RATE, PITCH_MAX);
118→            if (keys.e) pitchRef.current = Math.max(pitchRef.current - PITCH_RATE, -PITCH_MAX);
119→
120→            // ── Velocity ──────────────────────────────────────────────
121→            if (keys.w) {
122→                velocityRef.current = Math.min(velocityRef.current + ACCEL, MAX_SPEED);
123→            } else if (keys.s) {
124→                velocityRef.current = Math.max(velocityRef.current - BRAKE, 0);
125→            } else {
126→                velocityRef.current *= FRICTION;
127→                if (velocityRef.current < 0.01) velocityRef.current = 0;
128→            }
129→        }
130→
131→        // ── Magnetic pull (auto-aim toward docking target) ────────────
132→        if (dockState === 'magnet') {
133→            const tidx = dockingTargetIdxRef.current;
134→            if (tidx >= 0 && tidx < stars.length) {
135→                const target = stars[tidx];
136→                const relX = target.worldX - cam.x;
137→                const relY = target.worldY - cam.y;
138→                const relZ = target.worldZ - cam.z;
139→                const dist3D = Math.sqrt(relX * relX + relY * relY + relZ * relZ);
140→                if (dist3D > 0.01) {
141→                    const desiredYaw = Math.atan2(relX, relZ);
142→                    const desiredPitch = Math.asin(Math.max(-1, Math.min(1, relY / dist3D)));
143→                    // Proximity factor: 0 at MAGNET_THRESHOLD_Z, 1 at DOCKING_THRESHOLD_Z
144→                    const proximityFactor = Math.max(0, Math.min(1,
145→                        (MAGNET_THRESHOLD_Z - target.viewZ) / (MAGNET_THRESHOLD_Z - DOCKING_THRESHOLD_Z)
146→                    ));
147→                    const lerpFactor = MAGNET_STRENGTH * (0.3 + proximityFactor * 0.7);
148→                    // Normalize yaw difference to [-PI, PI]
149→                    let yawDiff = desiredYaw - yawRef.current;
150→                    while (yawDiff > Math.PI) yawDiff -= TWO_PI;
151→                    while (yawDiff < -Math.PI) yawDiff += TWO_PI;
152→                    yawRef.current += yawDiff * lerpFactor;
153→                    pitchRef.current += (desiredPitch - pitchRef.current) * lerpFactor;
154→                    pitchRef.current = Math.max(-PITCH_MAX, Math.min(PITCH_MAX, pitchRef.current));
155→                }
156→                // Disengage if target drifts beyond magnet zone
157→                if (target.viewZ > MAGNET_THRESHOLD_Z * 1.2 || target.viewZ < TARGET_Z_MIN) {
158→                    dockingStateRef.current = 'none';
159→                    dockingTargetIdxRef.current = -1;
160→                }
161→            }
162→        }
163→
164→        // ── Docking animation sequence ────────────────────────────────
165→        if (dockState === 'approaching' || dockState === 'flash') {
166→            const elapsed = performance.now() - dockingStartTimeRef.current;
167→            const tidx = dockingTargetIdxRef.current;
168→            const target = tidx >= 0 && tidx < stars.length ? stars[tidx] : null;
169→
170→            if (elapsed < 800 && target) {
171→                // Phase 1: Auto-approach (0-800ms)
172→                const relX = target.worldX - cam.x;
173→                const relY = target.worldY - cam.y;
174→                const relZ = target.worldZ - cam.z;
175→                const dist3D = Math.sqrt(relX * relX + relY * relY + relZ * relZ);
176→                if (dist3D > 0.01) {
177→                    const desiredYaw = Math.atan2(relX, relZ);
178→                    const desiredPitch = Math.asin(Math.max(-1, Math.min(1, relY / dist3D)));
179→                    let yawDiff = desiredYaw - yawRef.current;
180→                    while (yawDiff > Math.PI) yawDiff -= TWO_PI;
181→                    while (yawDiff < -Math.PI) yawDiff += TWO_PI;
182→                    yawRef.current += yawDiff * 0.12;
183→                    pitchRef.current += (desiredPitch - pitchRef.current) * 0.12;
184→                    pitchRef.current = Math.max(-PITCH_MAX, Math.min(PITCH_MAX, pitchRef.current));
185→                }
186→                velocityRef.current = Math.min(velocityRef.current + DOCK_ACCEL, DOCK_MAX_SPEED);
187→                // Quadratic ease-in scale: 1 → 9
188→                const t1 = elapsed / 800;
189→                dockingStarScaleRef.current = 1 + 8 * t1 * t1;
190→                dockingProgressRef.current = t1 * 0.6;
191→            } else if (elapsed < 1200 && target) {
192→                // Phase 2: Star explosion (800-1200ms)
193→                velocityRef.current *= 0.9;
194→                const t2 = (elapsed - 800) / 400;
195→                // Ease-out scale: 9 → 50
196→                const easeOut = 1 - (1 - t2) * (1 - t2);
197→                dockingStarScaleRef.current = 9 + 41 * easeOut;
198→                dockingProgressRef.current = 0.6 + t2 * 0.3;
199→            } else if (elapsed < 1700) {
200→                // Phase 3: White flash (1200-1700ms)
201→                velocityRef.current = 0;
202→                dockingStateRef.current = 'flash';
203→                const t3 = (elapsed - 1200) / 500;
204→                dockingProgressRef.current = 0.9 + t3 * 0.1;
205→            } else {
206→                // Done — stop loop immediately, then trigger callback exactly once
207→                isActiveRef.current = false;
208→                if (rafRef.current) { cancelAnimationFrame(rafRef.current); rafRef.current = null; }
209→                dockingStateRef.current = 'done';
210→                dockingProgressRef.current = 1;
211→                const cb = dockingCallbackRef.current;
212→                dockingCallbackRef.current = null;
213→                if (cb) cb();
214→                // Restore persistent auto-dock callback for next session
215→                if (autoDockCbRef.current) {
216→                    dockingCallbackRef.current = autoDockCbRef.current;
217→                }
218→                return; // do not reschedule
219→            }
220→        }
221→
222→        const yaw = yawRef.current;
223→        const pitch = pitchRef.current;
224→        const velocity = velocityRef.current;
225→
226→        // ── Position (move along forward vector) ─────────────────────
227→        const fwd = getForwardVector(yaw, pitch);
228→        cam.x += fwd.x * velocity;
229→        cam.y += fwd.y * velocity;
230→        cam.z += fwd.z * velocity;
231→
232→        // ── Pre-compute trig for view transform ──────────────────────
233→        const cosYaw = Math.cos(-yaw);
234→        const sinYaw = Math.sin(-yaw);
235→        const cosPitch = Math.cos(pitch);
236→        const sinPitch = Math.sin(pitch);
237→
238→        // ── View transform + recycling ───────────────────────────────
239→        const dockingActive = dockState !== 'none';
240→        const protectedIdx = dockingTargetIdxRef.current;
241→        for (let i = 0; i < stars.length; i++) {
242→            const star = stars[i];
243→
244→            // Translate to camera-relative
245→            const relX = star.worldX - cam.x;
246→            const relY = star.worldY - cam.y;
247→            const relZ = star.worldZ - cam.z;
248→
249→            // Yaw rotation (around Y axis)
250→            const rotX1 = relX * cosYaw + relZ * sinYaw;
251→            const rotZ1 = -relX * sinYaw + relZ * cosYaw;
252→
253→            // Pitch rotation (around X axis)
254→            const rotY2 = relY * cosPitch - rotZ1 * sinPitch;
255→            const viewZ = relY * sinPitch + rotZ1 * cosPitch;
256→
257→            // Cache on star for renderer
258→            star._rotX1 = rotX1;
259→            star._rotY2 = rotY2;
260→            star.viewZ = viewZ;
261→
262→            // Recycle stars that are behind camera or too far
263→            // Skip recycling for the docking target star
264→            if ((viewZ < MIN_VIEW_Z || viewZ > RECYCLE_Z) && !(dockingActive && i === protectedIdx)) {
265→                // Respawn ahead of camera using forward vector + random spread
266→                const dist = SPAWN_DIST * (0.5 + Math.random() * 0.5);
267→                const spreadX = (Math.random() - 0.5) * 2000;
268→                const spreadY = (Math.random() - 0.5) * 2000;
269→                star.worldX = cam.x + fwd.x * dist + spreadX;
270→                star.worldY = cam.y + fwd.y * dist + spreadY;
271→                star.worldZ = cam.z + fwd.z * dist + (Math.random() - 0.5) * 1000;
272→
273→                // Recompute view-space for the recycled position
274→                const rX = star.worldX - cam.x;
275→                const rY = star.worldY - cam.y;
276→                const rZ = star.worldZ - cam.z;
277→                const rX1 = rX * cosYaw + rZ * sinYaw;
278→                const rZ1 = -rX * sinYaw + rZ * cosYaw;
279→                star._rotX1 = rX1;
280→                star._rotY2 = rY * cosPitch - rZ1 * sinPitch;
281→                star.viewZ = rY * sinPitch + rZ1 * cosPitch;
282→            }
283→        }
284→
285→        // ── Sort (every N frames) ────────────────────────────────────
286→        frameRef.current++;
287→        if (frameRef.current % SORT_INTERVAL === 0) {
288→            sortStars();
289→        }
290→
291→        // ── Target detection ─────────────────────────────────────────
292→        const cx = size.width / 2;
293→        const cy = size.height / 2;
294→        const focalLength = size.width * 0.6;
295→        let bestIdx = -1;
296→        let bestDist = TARGET_DIST_MAX;
297→
298→        for (let i = 0; i < stars.length; i++) {
299→            const star = stars[i];
300→            if (star.viewZ < TARGET_Z_MIN) continue;
301→            const projX = cx + (star._rotX1 / star.viewZ) * focalLength;
302→            const projY = cy - (star._rotY2 / star.viewZ) * focalLength;
303→            const dx = projX - cx;
304→            const dy = projY - cy;
305→            const dist = Math.sqrt(dx * dx + dy * dy);
306→            if (dist < bestDist) {
307→                bestDist = dist;
308→                bestIdx = i;
309→            }
310→        }
311→        targetIndexRef.current = bestIdx;
312→
313→        // ── Docking detection ─────────────────────────────────────────
314→        // Read live ref (not stale snapshot) to respect triggerDocking() calls from user input
315→        const cooldownActive = performance.now() < dockCooldownRef.current;
316→        if (dockingStateRef.current === 'none' && bestIdx >= 0 && !cooldownActive) {
317→            const targetStar = stars[bestIdx];
318→            const viewZ = targetStar.viewZ;
319→            if (viewZ < DOCKING_THRESHOLD_Z && bestDist < DOCKING_CENTER_MAX) {
320→                // Close enough and centered — auto-dock
321→                dockingStateRef.current = 'approaching';
322→                dockingTargetIdxRef.current = bestIdx;
323→                dockingStartTimeRef.current = performance.now();
324→                dockingProgressRef.current = 0;
325→                dockingStarScaleRef.current = 1;
326→                inputFrozenRef.current = true;
327→            } else if (viewZ < MAGNET_THRESHOLD_Z && viewZ > DOCKING_THRESHOLD_Z) {
328→                // In magnet zone — engage gentle pull
329→                dockingStateRef.current = 'magnet';
330→                dockingTargetIdxRef.current = bestIdx;
331→            }
332→        }
333→        // Disengage magnet if best target changes
334→        if (dockingStateRef.current === 'magnet' && bestIdx !== dockingTargetIdxRef.current) {
335→            dockingStateRef.current = 'none';
336→            dockingTargetIdxRef.current = -1;
337→            dockCooldownRef.current = performance.now() + 500; // brief cooldown after target switch
338→        }
339→        // Transition magnet → approaching when within docking threshold and centered
340→        if (dockingStateRef.current === 'magnet') {
341→            const tidx = dockingTargetIdxRef.current;
342→            if (tidx >= 0 && tidx < stars.length) {
343→                const mTarget = stars[tidx];
344→                if (!cooldownActive && mTarget.viewZ < DOCKING_THRESHOLD_Z && mTarget.viewZ > TARGET_Z_MIN) {
345→                    const mProjX = cx + (mTarget._rotX1 / mTarget.viewZ) * focalLength;
346→                    const mProjY = cy - (mTarget._rotY2 / mTarget.viewZ) * focalLength;
347→                    const mDist = Math.sqrt((mProjX - cx) ** 2 + (mProjY - cy) ** 2);
348→                    if (mDist < DOCKING_CENTER_MAX) {
349→                        dockingStateRef.current = 'approaching';
350→                        dockingStartTimeRef.current = performance.now();
351→                        dockingProgressRef.current = 0;
352→                        dockingStarScaleRef.current = 1;
353→                        inputFrozenRef.current = true;
354→                    }
355→                }
356→            }
357→        }
358→
359→        // ── Redraw ───────────────────────────────────────────────────
360→        if (layerRef.current) {
361→            layerRef.current.batchDraw();
362→        }
363→
364→        rafRef.current = requestAnimationFrame(tick);
365→    }, [sortStars]);
366→
367→    const enter = useCallback((galaxyPosts, galaxyCenter, stageSize) => {
368→        // Clean up any existing loop/listeners before re-entering
369→        isActiveRef.current = false;
370→        if (rafRef.current) { cancelAnimationFrame(rafRef.current); rafRef.current = null; }
371→        if (onKeyDownRef.current) {
372→            window.removeEventListener('keydown', onKeyDownRef.current);
373→            window.removeEventListener('keyup', onKeyUpRef.current);
374→            onKeyDownRef.current = null; onKeyUpRef.current = null;
375→        }
376→
377→        stageSizeRef.current = stageSize;
378→        camPosRef.current = { x: galaxyCenter.x, y: galaxyCenter.y, z: 0 };
379→        galaxyCenterRef.current = { x: galaxyCenter.x, y: galaxyCenter.y };
380→        yawRef.current = 0;
381→        pitchRef.current = 0;
382→        velocityRef.current = 0;
383→        frameRef.current = 0;
384→        targetIndexRef.current = -1;
385→
386→        // Reset docking state
387→        dockingStateRef.current = 'none';
388→        dockingTargetIdxRef.current = -1;
389→        dockingProgressRef.current = 0;
390→        dockingStarScaleRef.current = 1;
391→        inputFrozenRef.current = false;
392→        dockCooldownRef.current = 0;
393→
394→        // Build star array from posts — distributed in 3D volume
395→        const stars = [];
396→        for (let i = 0; i < galaxyPosts.length; i++) {
397→            const post = galaxyPosts[i];
398→            const uid = post.users?.id ?? post.user_id;
399→            const likeCount = post.like_count != null
400→                ? post.like_count
401→                : (Array.isArray(post.likes) && post.likes[0]?.count != null
402→                    ? post.likes[0].count : 0);
403→            const color = getStarColor(uid);
404→            const rng = seededRandom(simpleHash(post.id || String(i)));
405→            // Always consume two RNG calls for X/Y so worldZ gets a consistent 3rd draw
406→            const rngX = rng();
407→            const rngY = rng();
408→            stars.push({
409→                postId: post.id,
410→                worldX: post.universe_x ?? post.display_x ?? galaxyCenter.x + (rngX - 0.5) * 2000,
411→                worldY: post.universe_y ?? post.display_y ?? galaxyCenter.y + (rngY - 0.5) * 2000,
412→                worldZ: (rng() - 0.5) * SPAWN_DIST * 2, // ±SPAWN_DIST from camera z=0
413→                viewZ: 0,
414→                _rotX1: 0,
415→                _rotY2: 0,
416→                color,
417→                colorRgb: parseHex(color),
418→                radius: getStarRadius(likeCount),
419→                title: post.title || 'Untitled',
420→                authorName: post.users?.name || post.user_name || 'Anonymous',
421→                post,
422→            });
423→        }
424→
425→        starsRef.current = stars;
426→
427→        // Build sorted indices (far → near by viewZ, will be sorted properly on first tick)
428→        const indices = new Array(stars.length);
429→        for (let i = 0; i < stars.length; i++) indices[i] = i;
430→        sortedIndicesRef.current = indices;
431→
432→        // Key listeners
433→        const onKeyDown = (e) => {
434→            const key = e.key.toLowerCase();
435→            if (key === 'w') keysRef.current.w = true;
436→            if (key === 's') keysRef.current.s = true;
437→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = true;
438→            if (key === 'd' || key === 'arrowright') keysRef.current.d = true;
439→            if (key === 'q' || key === 'arrowup') keysRef.current.q = true;
440→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = true;
441→        };
442→        const onKeyUp = (e) => {
443→            const key = e.key.toLowerCase();
444→            if (key === 'w') keysRef.current.w = false;
445→            if (key === 's') keysRef.current.s = false;
446→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = false;
447→            if (key === 'd' || key === 'arrowright') keysRef.current.d = false;
448→            if (key === 'q' || key === 'arrowup') keysRef.current.q = false;
449→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = false;
450→        };
451→
452→        onKeyDownRef.current = onKeyDown;
453→        onKeyUpRef.current = onKeyUp;
454→        window.addEventListener('keydown', onKeyDown);
455→        window.addEventListener('keyup', onKeyUp);
456→
457→        // Reset keys
458→        keysRef.current = { w: false, s: false, a: false, d: false, q: false, e: false };
459→        isActiveRef.current = true;
460→
461→        // Start rAF
462→        rafRef.current = requestAnimationFrame(tick);
463→    }, [tick]);
464→
465→    const exit = useCallback(() => {
466→        isActiveRef.current = false;
467→        if (rafRef.current) {
468→            cancelAnimationFrame(rafRef.current);
469→            rafRef.current = null;
470→        }
471→        // Remove key listeners
472→        if (onKeyDownRef.current) {
473→            window.removeEventListener('keydown', onKeyDownRef.current);
474→            window.removeEventListener('keyup', onKeyUpRef.current);
475→            onKeyDownRef.current = null;
476→            onKeyUpRef.current = null;
477→        }
478→        keysRef.current = { w: false, s: false, a: false, d: false, q: false, e: false };
479→        // Reset docking
480→        dockingStateRef.current = 'none';
481→        dockingTargetIdxRef.current = -1;
482→        dockingProgressRef.current = 0;
483→        dockingStarScaleRef.current = 1;
484→        inputFrozenRef.current = false;
485→        dockingCallbackRef.current = null;
486→    }, []);
487→
488→    const project = useCallback((star, cx, cy) => {
489→        if (star.viewZ <= MIN_VIEW_Z) return null; // behind camera
490→
491→        const stageWidth = stageSizeRef.current.width;
492→        const focalLength = stageWidth * 0.6; // ~80° FOV
493→        const projX = cx + (star._rotX1 / star.viewZ) * focalLength;
494→        const projY = cy - (star._rotY2 / star.viewZ) * focalLength; // negate Y for screen coords
495→        const scale = focalLength / star.viewZ;
496→
497→        return { projX, projY, scale };
498→    }, []);
499→
500→    const getTargetedPost = useCallback(() => {
501→        const idx = targetIndexRef.current;
502→        if (idx < 0 || idx >= starsRef.current.length) return null;
503→        return starsRef.current[idx].post;
504→    }, []);
505→
506→    const getSpeedRatio = useCallback(() => {
507→        return velocityRef.current / MAX_SPEED;
508→    }, []);
509→
510→    const getDockingState = useCallback(() => {
511→        return dockingStateRef.current;
512→    }, []);
513→
514→    const getSessionSnapshot = useCallback(() => {
515→        const cam = camPosRef.current;
516→        const gc = galaxyCenterRef.current;
517→        // Back up camera along reverse forward vector so restore doesn't land inside the star
518→        const RESTORE_BACK_OFFSET = 60;
519→        const fwd = getForwardVector(yawRef.current, pitchRef.current);
520→        return {
521→            camX: cam.x - fwd.x * RESTORE_BACK_OFFSET,
522→            camY: cam.y - fwd.y * RESTORE_BACK_OFFSET,
523→            camZ: cam.z - fwd.z * RESTORE_BACK_OFFSET,
524→            yaw: yawRef.current,
525→            pitch: pitchRef.current,
526→            velocity: 0,
527→            galaxyCenterX: gc.x,
528→            galaxyCenterY: gc.y,
529→            timestamp: Date.now(),
530→        };
531→    }, []);
532→
533→    const restoreFromSnapshot = useCallback((snapshot, galaxyPosts, stageSize) => {
534→        // Clean up any existing loop/listeners before restoring
535→        isActiveRef.current = false;
536→        if (rafRef.current) { cancelAnimationFrame(rafRef.current); rafRef.current = null; }
537→        if (onKeyDownRef.current) {
538→            window.removeEventListener('keydown', onKeyDownRef.current);
539→            window.removeEventListener('keyup', onKeyUpRef.current);
540→            onKeyDownRef.current = null; onKeyUpRef.current = null;
541→        }
542→
543→        stageSizeRef.current = stageSize;
544→        camPosRef.current = { x: snapshot.camX, y: snapshot.camY, z: snapshot.camZ };
545→        yawRef.current = snapshot.yaw;
546→        pitchRef.current = snapshot.pitch;
547→        velocityRef.current = 0; // smooth re-entry
548→        frameRef.current = 0;
549→        targetIndexRef.current = -1;
550→
551→        // Reset docking state
552→        dockingStateRef.current = 'none';
553→        dockingTargetIdxRef.current = -1;
554→        dockingProgressRef.current = 0;
555→        dockingStarScaleRef.current = 1;
556→        inputFrozenRef.current = false;
557→        // Suppress auto-dock for 2s after restore to prevent redirect loop
558→        dockCooldownRef.current = performance.now() + 2000;
559→
560→        // Build star array — use stored galaxy center for consistent star placement
561→        const galaxyCenter = snapshot.galaxyCenterX != null
562→            ? { x: snapshot.galaxyCenterX, y: snapshot.galaxyCenterY }
563→            : { x: snapshot.camX, y: snapshot.camY };
564→        galaxyCenterRef.current = { x: galaxyCenter.x, y: galaxyCenter.y };
565→        const stars = [];
566→        for (let i = 0; i < galaxyPosts.length; i++) {
567→            const post = galaxyPosts[i];
568→            const uid = post.users?.id ?? post.user_id;
569→            const likeCount = post.like_count != null
570→                ? post.like_count
571→                : (Array.isArray(post.likes) && post.likes[0]?.count != null
572→                    ? post.likes[0].count : 0);
573→            const color = getStarColor(uid);
574→            const rng = seededRandom(simpleHash(post.id || String(i)));
575→            // Always consume two RNG calls for X/Y so worldZ gets a consistent 3rd draw
576→            const rngX = rng();
577→            const rngY = rng();
578→            stars.push({
579→                postId: post.id,
580→                worldX: post.universe_x ?? post.display_x ?? galaxyCenter.x + (rngX - 0.5) * 2000,
581→                worldY: post.universe_y ?? post.display_y ?? galaxyCenter.y + (rngY - 0.5) * 2000,
582→                worldZ: (rng() - 0.5) * SPAWN_DIST * 2,
583→                viewZ: 0,
584→                _rotX1: 0,
585→                _rotY2: 0,
586→                color,
587→                colorRgb: parseHex(color),
588→                radius: getStarRadius(likeCount),
589→                title: post.title || 'Untitled',
590→                authorName: post.users?.name || post.user_name || 'Anonymous',
591→                post,
592→            });
593→        }
594→
595→        starsRef.current = stars;
596→
597→        const indices = new Array(stars.length);
598→        for (let i = 0; i < stars.length; i++) indices[i] = i;
599→        sortedIndicesRef.current = indices;
600→
601→        // Key listeners
602→        const onKeyDown = (e) => {
603→            const key = e.key.toLowerCase();
604→            if (key === 'w') keysRef.current.w = true;
605→            if (key === 's') keysRef.current.s = true;
606→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = true;
607→            if (key === 'd' || key === 'arrowright') keysRef.current.d = true;
608→            if (key === 'q' || key === 'arrowup') keysRef.current.q = true;
609→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = true;
610→        };
611→        const onKeyUp = (e) => {
612→            const key = e.key.toLowerCase();
613→            if (key === 'w') keysRef.current.w = false;
614→            if (key === 's') keysRef.current.s = false;
615→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = false;
616→            if (key === 'd' || key === 'arrowright') keysRef.current.d = false;
617→            if (key === 'q' || key === 'arrowup') keysRef.current.q = false;
618→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = false;
619→        };
620→
621→        onKeyDownRef.current = onKeyDown;
622→        onKeyUpRef.current = onKeyUp;
623→        window.addEventListener('keydown', onKeyDown);
624→        window.addEventListener('keyup', onKeyUp);
625→
626→        keysRef.current = { w: false, s: false, a: false, d: false, q: false, e: false };
627→        isActiveRef.current = true;
628→
629→        rafRef.current = requestAnimationFrame(tick);
630→    }, [tick]);
631→
632→    const setDockingCallback = useCallback((cb) => {
633→        // Don't overwrite a callback that's already mid-animation
634→        const state = dockingStateRef.current;
635→        if (state === 'none' || state === 'magnet') {
636→            dockingCallbackRef.current = cb;
637→        }
638→        // Always store as persistent auto-dock callback
639→        autoDockCbRef.current = cb;
640→    }, []);
641→
642→    const abortDocking = useCallback(() => {
643→        if (dockingStateRef.current === 'magnet') {
644→            dockingStateRef.current = 'none';
645→            dockingTargetIdxRef.current = -1;
646→            dockingProgressRef.current = 0;
647→            dockingStarScaleRef.current = 1;
648→        }
649→        // Approaching/flash are non-interruptible
650→    }, []);
651→
652→    const triggerDocking = useCallback((targetIdx, callback) => {
653→        if (dockingStateRef.current !== 'none' && dockingStateRef.current !== 'magnet') return;
654→        dockingStateRef.current = 'approaching';
655→        dockingTargetIdxRef.current = targetIdx;
656→        dockingStartTimeRef.current = performance.now();
657→        dockingProgressRef.current = 0;
658→        dockingStarScaleRef.current = 1;
659→        inputFrozenRef.current = true;
660→        if (callback) dockingCallbackRef.current = callback;
661→    }, []);
662→
663→    return useMemo(() => ({
664→        enter,
665→        exit,
666→        layerRef,
667→        starsRef,
668→        sortedIndicesRef,
669→        rocketPos: camPosRef,
670→        heading: yawRef,
671→        pitch: pitchRef,
672→        velocity: velocityRef,
673→        targetIndexRef,
674→        stageSizeRef,
675→        project,
676→        isActive: isActiveRef,
677→        getTargetedPost,
678→        getSpeedRatio,
679→        // Docking API
680→        getDockingState,
681→        getSessionSnapshot,
682→        restoreFromSnapshot,
683→        setDockingCallback,
684→        abortDocking,
685→        triggerDocking,
686→        dockingStateRef,
687→        dockingTargetIdxRef,
688→        dockingProgressRef,
689→        dockingStarScaleRef,
690→        inputFrozenRef,
691→    }), [enter, exit, project, getTargetedPost, getSpeedRatio, getDockingState,
692→         getSessionSnapshot, restoreFromSnapshot, setDockingCallback, abortDocking, triggerDocking]);
693→};
694→
695→export default useRocketMode;
