 210→    const getComputedStarPosition = useCallback((post) => {
 211→        if (!post) return null;
 212→
 213→        const uid = post.users?.id ?? post.user_id;
 214→        const hashGal = userHomeCoords(uid);
 215→        const animGal = galaxyPositions.get(uid);
 216→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
 217→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
 218→        const pull = starPullOffsets.get(post.id);
 219→
 220→        const baseX = post.universe_x ?? post.display_x;
 221→        const baseY = post.universe_y ?? post.display_y;
 222→        if (baseX == null || baseY == null) return null;
 223→
 224→        return {
 225→            x: baseX + galDx + (pull?.dx ?? 0),
 226→            y: baseY + galDy + (pull?.dy ?? 0),
 227→        };
 228→    }, [galaxyPositions, starPullOffsets]);
